import{_ as e,o as t,c as i,a}from"./app.c5171353.js";const y=JSON.parse('{"title":"Crustifer v. SpicyBoy, Oct 2017","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/crustifer_v_spicyboy_oct_2017.md","lastUpdated":1666046177000}'),r={name:"government/court-cases-precedents/crustifer_v_spicyboy_oct_2017.md"},s=a('<h1 id="crustifer-v-spicyboy-oct-2017" tabindex="-1">Crustifer v. SpicyBoy, Oct 2017 <a class="header-anchor" href="#crustifer-v-spicyboy-oct-2017" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: TheOrangeWizard</p><p><strong>Date</strong>: 14th October 2017</p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><ol><li>SpicyBoy with the theft of a &#39;large&#39; amount of diamond blocks and other valuables, via stealing a deathpile and breaking an un-matured diamond reinforced chest.</li></ol><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><p>SpicyBoy pleads not guilty on reason of total denial of culpability, saying that he didn&#39;t steal anything and that the items must have despawned.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><p>SpicyBoy alleges complete innocence</p></li><li><p>Crustifer denies this as a possibility</p></li><li><p>SpicyBoy repeats his denial</p></li><li><p>Crustifer says that he had &#39;just&#39; reinforced the chest before dying and that after he came to retrieve his deathpile the chest was broken. This interval would leave enough time for spicy to have broken the chest and stolen the materials.</p></li><li><p>SpicyBoy tells Crustifer to &#39;fuck off kid&#39; and that &#39;i bet he doesnt even know what he lost&#39;</p></li><li><p>Crustifer then claims that &#39;i know what i lost of value&#39;</p></li><li><p>SpicyBoy is arrested via pearling and his house searched, discovering the stolen items</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><p>Crustifer&#39;s items are returned and SpicyBoy is unpearled. Any further thieving by SpicyBoy will be met with one week of end time.</p>',11),o=[s];function n(c,l,h,d,p,u){return t(),i("div",null,o)}const _=e(r,[["render",n]]);export{y as __pageData,_ as default};
